#!/usr/bin/env node
// Verify every golden-corpus expectation against the ORIGINAL JS chord2mml.
//
// The corpus expectations were generated by executing the JS implementation;
// this script re-runs that comparison so future corpus edits (or upstream JS
// changes) can be audited.
//
// IMPORTANT: the JS repo's committed dist/ can lag behind its src/ (it did:
// dist built 2026-03-07, src changed through 2026-04-18). Always verify
// against a FRESH bundle of the src, e.g.:
//
//   npx esbuild path/to/chord2mml/src/chord2mml.ts --bundle --format=esm \
//     --outfile=/tmp/chord2mml-fresh.mjs \
//     --alias:./chord2mml_chord2ast.cjs=path/to/chord2mml/src/chord2mml_chord2ast.mjs
//
// Usage: node scripts/verify-corpus-vs-js.mjs <path-to-fresh-chord2mml-bundle.mjs>
import { readFile, readdir } from 'fs/promises';
import { pathToFileURL } from 'url';

const bundlePath = process.argv[2];
if (!bundlePath) {
  console.error('Usage: node scripts/verify-corpus-vs-js.mjs <fresh-chord2mml-bundle.mjs>');
  process.exit(1);
}

const mod = await import(pathToFileURL(bundlePath).href);
const chord2mml = mod.chord2mml ?? mod;

const corpusDir = new URL('../chord2mml-core/tests/corpus/', import.meta.url);
const files = (await readdir(corpusDir)).filter((f) => f.endsWith('.json')).sort();

// Inputs JS rejects but this port accepts by design (documented supersets)
const RUST_EXTENSION_FILES = new Set(['rust-extensions.json']);

let mismatches = 0;
let total = 0;
let skipped = 0;
for (const file of files) {
  if (RUST_EXTENSION_FILES.has(file)) {
    const cases = JSON.parse(await readFile(new URL(file, corpusDir), 'utf8'));
    skipped += cases.length;
    continue;
  }
  const cases = JSON.parse(await readFile(new URL(file, corpusDir), 'utf8'));
  for (const { input, expected } of cases) {
    total++;
    let actual;
    try {
      actual = chord2mml.parse(input);
    } catch (e) {
      console.log(`✗ [${file}] ${input}: JS threw: ${e.message}`);
      mismatches++;
      continue;
    }
    if (actual !== expected) {
      console.log(`✗ [${file}] ${input}: corpus has ${expected}, JS gives ${actual}`);
      mismatches++;
    }
  }
}

if (mismatches > 0) {
  console.error(`${mismatches}/${total} corpus expectations differ from the JS implementation`);
  process.exit(1);
}
console.log(
  `OK: all ${total} corpus expectations match the JS implementation` +
    ` (${skipped} Rust-extension cases skipped)`
);
